ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?office a :Office .
    ?graphic_designers a :Graphic_Designers .
    ?graphic_designers p:hasOffice ?office .
    ?graphic_designers p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?office a :Office .
    ?web_developers a :Web_Developers .
    ?web_developers p:hasOffice ?office .
    ?web_developers p:name ?name .
    ?office p:address ?address_f .
    FILTER(STR(?address_f) = "3/10 New York Avenue")
    BIND(?name AS ?o0)
  }
} }
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?office a :Office .
    ?graphic_designers a :Graphic_Designers .
    ?graphic_designers p:hasOffice ?office .
    ?graphic_designers p:name ?name .
    ?office p:address ?address_f .
    FILTER(STR(?address_f) = "3/10 New York Avenue")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?office a :Office .
    ?web_developers a :Web_Developers .
    ?web_developers p:hasOffice ?office .
    ?web_developers p:name ?name .
    ?office p:address ?address_f .
    FILTER(STR(?address_f) = "3/10 New York Avenue")
    BIND(?name AS ?o0)
  }
} }
}
